const task = $json.task;

return [{
  json: {
    text: "Отмечено как завершённое ✅\n" + task
  }
}];

const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        text: "У тебя нет активных напоминаний ✅"
      }
    }
  ];
}

const timezone = $node["Execute a SQL query1"].json.timezone || "UTC";
const now = new Date();

function formatLocalDateKey(date, tz) {
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).format(date);
}

function formatTime(date, tz) {
  return new Intl.DateTimeFormat("ru-RU", {
    timeZone: tz,
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).format(date);
}

function formatDayMonth(date, tz) {
  return new Intl.DateTimeFormat("ru-RU", {
    timeZone: tz,
    day: "numeric",
    month: "long"
  }).format(date);
}

const nowKey = formatLocalDateKey(now, timezone);

const overdue = [];
const upcoming = [];

for (const item of items) {
  const task = item.json.task;
  const type = item.json.reminder_type;
  const remindAt = new Date(item.json.remind_at);
  const icon = type === "event" ? "📅" : "📝";
  const recurring = item.json.is_recurring ? " 🔁" : "";

  const remindKey = formatLocalDateKey(remindAt, timezone);
  const time = formatTime(remindAt, timezone);

  let prefix = "";

  if (remindKey === nowKey) {
    prefix = time;
  } else {
    prefix = formatDayMonth(remindAt, timezone) + " в " + time;
  }

  const line = icon + recurring + " " + prefix + " — " + task;

  if (remindAt < now) {
    overdue.push(line);
  } else {
    upcoming.push(line);
  }
}

let text = "";

if (overdue.length > 0) {
  text += "Вот что у тебя осталось:\n\n";
  text += overdue.join("\n");
}

if (upcoming.length > 0) {
  if (overdue.length > 0) {
    text += "\n\n";
  }
  text += "📋 Активные:\n";
  text += upcoming.join("\n");
}

return [
  {
    json: {
      text: text
    }
  }
];
